'use client';
// src/hooks/useKiosk.js
// Central state management hook for the NLI Kiosk application

import { useState, useRef, useCallback, useEffect } from 'react';
import { analyzeEnglishText, getBaseLangCode } from '../data/nliRules';
import { CHATBOT_DATABASE, getChatbotDbKey } from '../data/chatbotData';

export const PRESETS = [
  { lang: 'tl', flag: '🇵🇭', label: 'PHL (Tagalog)', snippet: '"My sister he will..."', text: 'My sister he will arriving at Friday in the hotel, so I will going to pick up.' },
  { lang: 'zh', flag: '🇨🇳', label: 'CHN (Chinese)', snippet: '"Yesterday flight cancel..."', text: 'Yesterday my flight cancel and I very like terminal two. My friend he say flight is delay.' },
  { lang: 'ko', flag: '🇰🇷', label: 'KOR (Korean)', snippet: '"I handphone lost..."', text: 'I handphone lost. Where is booking do counter? Give me service coffee please.' },
  { lang: 'ja', flag: '🇯🇵', label: 'JPN (Japanese)', snippet: '"Where is toilet please..."', text: 'Where is toilet please? I seek fright details. Train station terminal please.' },
  { lang: 'id', flag: '🇮🇩', label: 'IDN (Indonesian)', snippet: '"I lost at terminal..."', text: 'I lost at terminal, flight very late. Two bag missing. I join you to gates?' },
  { lang: 'ur', flag: '🇵🇰', label: 'PAK (Urdu)', snippet: '"You check my flight..."', text: 'You check my flight details, is it? We need to discuss about gate. Do one thing, help me.' },
  { lang: 'th', flag: '🇹🇭', label: 'THA (Thai)', snippet: '"No have ticket same-same..."', text: 'No have ticket same-same my friend. I like airport services very. Terminal far very.' },
  { lang: 'en', flag: '🇬🇧', label: 'Native English', snippet: '"I need to check..."', text: 'Hello, I need to check my flight status for flight SA405 to London. Thank you.' },
];

export default function useKiosk() {
  // --- Screen State ---
  const [currentScreen, setCurrentScreen] = useState('WELCOME'); // 'WELCOME' | 'PORTAL'
  
  // --- Language State ---
  const [selectedLanguage, setSelectedLanguage] = useState('en');
  const [detectedLanguage, setDetectedLanguage] = useState(null);
  
  // --- Status State ---
  const [kioskStatus, setKioskStatus] = useState('ready'); // 'ready' | 'listening' | 'thinking' | 'prompt'
  
  // --- Input State ---
  const [inputText, setInputText] = useState('');
  const [isListening, setIsListening] = useState(false);
  
  // --- Analytics State ---
  const [showAnalytics, setShowAnalytics] = useState(false);
  const [highlightedHtml, setHighlightedHtml] = useState('');
  const [probabilities, setProbabilities] = useState([]);
  const [rawMatches, setRawMatches] = useState([]);
  
  // --- Suggestion Overlay ---
  const [showSuggestion, setShowSuggestion] = useState(false);
  const [suggestionData, setSuggestionData] = useState(null);
  
  // --- Modal State ---
  const [activeModal, setActiveModal] = useState(null); // 'flight' | 'map' | 'ticket' | 'support' | null
  
  // --- Chatbot State ---
  const [chatMessages, setChatMessages] = useState([]);
  
  // --- Portal Language Data (the full localized portal) ---
  const [portalLang, setPortalLang] = useState(null);

  // --- Speech Recognition ---
  const recognizerRef = useRef(null);
  const highestInterimRef = useRef(null);

  // --- Toast notifications ---
  const [toast, setToast] = useState(null);

  const showToast = useCallback((message, type = 'info') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 5000);
  }, []);

  // Initialize speech recognition
  useEffect(() => {
    const SpeechObj = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechObj) return;
    try {
      const recognizer = new SpeechObj();
      recognizer.continuous = false;
      recognizer.interimResults = true;
      recognizer.lang = 'en-US';

      recognizer.onstart = () => {
        setIsListening(true);
        highestInterimRef.current = null;
        setKioskStatus('listening');
      };

      recognizer.onresult = (event) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        const activeText = final || interim;
        if (activeText) {
          setInputText(activeText);
          const analysis = analyzeEnglishText(activeText);
          if (analysis.detected && (!highestInterimRef.current || analysis.detected.confidence > highestInterimRef.current.confidence)) {
            highestInterimRef.current = analysis.detected;
          }
        }
      };

      recognizer.onerror = (event) => {
        setIsListening(false);
        setKioskStatus('ready');
        if (event.error === 'not-allowed') showToast('Microphone access blocked! Allow mic permissions in your browser.', 'error');
        else if (event.error === 'no-speech') showToast('No speech detected. Check your mic connection.', 'error');
        else if (event.error === 'network') showToast('Network error! Speech recognition blocked. Try typing instead.', 'error');
        else showToast('Speech capture failed. Please try typing.', 'error');
      };

      recognizer.onend = () => {
        setIsListening(false);
        setKioskStatus('ready');
        setTimeout(() => {
          setInputText(prev => {
            if (prev.trim().length > 3) processText(prev, true);
            return prev;
          });
        }, 300);
      };

      recognizerRef.current = recognizer;
    } catch (err) {
      console.warn('Speech init failed:', err);
    }
  }, []);

  const toggleListening = useCallback(() => {
    if (!recognizerRef.current) {
      showToast('Microphone not supported in this browser.', 'error');
      return;
    }
    if (isListening) {
      recognizerRef.current.stop();
    } else {
      setInputText('');
      try { recognizerRef.current.start(); } catch (e) { console.warn(e); }
    }
  }, [isListening, showToast]);

  const processText = useCallback((text, triggerModal = false) => {
    if (!text || !text.trim()) return;
    setKioskStatus('thinking');
    setShowAnalytics(true);

    const analysis = analyzeEnglishText(text);
    setHighlightedHtml(analysis.highlightedHtml);
    setProbabilities(analysis.probabilities);
    setRawMatches(analysis.rawMatches);
    setKioskStatus('ready');

    if (triggerModal) {
      const resolved = analysis.detected || highestInterimRef.current;
      highestInterimRef.current = null;

      if (resolved) {
        setTimeout(() => {
          setSuggestionData({ detected: resolved, probabilities: analysis.probabilities });
          setShowSuggestion(true);
          setKioskStatus('prompt');
        }, 1500);
      } else {
        setTimeout(() => switchToPortal('en'), 1500);
      }
    }
  }, []);

  const submitInput = useCallback((text, trigger = true) => {
    processText(text, trigger);
  }, [processText]);

  const switchToPortal = useCallback((langCode) => {
    setSelectedLanguage(langCode);
    setShowSuggestion(false);
    setShowAnalytics(false);
    setCurrentScreen('PORTAL');
    setKioskStatus('ready');

    // Set portal language display data
    const base = getBaseLangCode(langCode);
    setPortalLang({ code: langCode, base });
  }, []);

  const resetSession = useCallback(() => {
    setCurrentScreen('WELCOME');
    setSelectedLanguage('en');
    setDetectedLanguage(null);
    setInputText('');
    setShowAnalytics(false);
    setHighlightedHtml('');
    setProbabilities([]);
    setRawMatches([]);
    setShowSuggestion(false);
    setSuggestionData(null);
    setActiveModal(null);
    setChatMessages([]);
    setPortalLang(null);
    setKioskStatus('ready');
  }, []);

  const openModal = useCallback((modalName) => {
    setActiveModal(modalName);
    if (modalName === 'support') {
      // Init chatbot
      const dbKey = getChatbotDbKey(selectedLanguage);
      const db = CHATBOT_DATABASE[dbKey] || CHATBOT_DATABASE.en;
      setChatMessages([{ sender: 'bot', text: db.welcome }]);
    }
  }, [selectedLanguage]);

  const closeModal = useCallback(() => setActiveModal(null), []);

  const sendChatMessage = useCallback((query) => {
    if (!query.trim()) return;
    const userMsg = { sender: 'user', text: query };
    setChatMessages(prev => [...prev, userMsg]);

    setTimeout(() => {
      const dbKey = getChatbotDbKey(selectedLanguage);
      const db = CHATBOT_DATABASE[dbKey] || CHATBOT_DATABASE.en;
      const lowerQuery = query.toLowerCase();
      let foundAnswer = null;
      for (const item of db.answers) {
        if (item.keys.some(k => lowerQuery.includes(k))) {
          foundAnswer = item.ans;
          break;
        }
      }
      const reply = foundAnswer || db.fallback;
      setChatMessages(prev => [...prev, { sender: 'bot', text: reply }]);
    }, 750);
  }, [selectedLanguage]);

  return {
    // State
    currentScreen, selectedLanguage, detectedLanguage, kioskStatus,
    inputText, setInputText, isListening,
    showAnalytics, highlightedHtml, probabilities, rawMatches,
    showSuggestion, setSuggestion: setShowSuggestion, suggestionData,
    activeModal, chatMessages,
    portalLang, toast,
    // Actions
    toggleListening, submitInput, processText,
    switchToPortal, resetSession,
    openModal, closeModal, sendChatMessage, showToast,
  };
}
